module binary_counter(
    input       clk   ,
    input       reset ,

    output reg [3:0] count
);

    // 4-bit binary counter with asynchronous reset
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
        if (reset) begin
            count <= 4'b0000;
        end else begin
            count <= count + 1;
        end
    end

endmodule
